// Normalise incoming payload from matrix-bridge.
// body: {operator_mxid, source_room_id, command, arg, session_id}

const body = $input.first().json.body || $input.first().json;
const op   = (body.operator_mxid || '').trim();
const room = (body.source_room_id || '').trim();
const cmd  = (body.command || '').trim().toLowerCase();
const arg  = String(body.arg || '').trim();
const sid  = Number(body.session_id || 0);

function qesc(s) { return String(s).replace(/'/g, "'\\''"); }

let flags;
switch (cmd) {
  case 'learn':
    if (arg === 'pause')       flags = '--pause';
    else if (arg === 'resume') flags = '--resume';
    else if (arg === 'public on')  flags = '--public-on';
    else if (arg === 'public off') flags = '--public-off';
    else if (arg)              flags = "--lesson --topic '" + qesc(arg) + "'";
    else                       flags = '--next';
    break;
  case 'quiz':
    flags = arg ? ("--quiz --topic '" + qesc(arg) + "'") : '--quiz';
    break;
  case 'grade':
    flags = "--grade --session-id " + sid + " --answer '" + qesc(arg) + "'";
    break;
  case 'progress':
    flags = (arg === 'public') ? '--progress --public' : '--progress';
    break;
  case 'digest':
  case 'class-digest':
  case 'leaderboard':
    flags = '--class-digest';
    break;
  case 'skip':
  case 'teach':
  case 'next':
  default:
    flags = '--next';
}

let argv = flags;
if (op)   argv += " --operator '" + qesc(op) + "'";
if (room) argv += " --source-room '" + qesc(room) + "'";

return [{ json: { operator_mxid: op, source_room_id: room, command: cmd, argv } }];

// Pass-through — the SSH node already ran; teacher-agent.py already posted
// its own Matrix messages. We relay the JSON status so n8n execution logs
// show failures cleanly in the UI.
const stdout = $input.first().json.stdout || '';
let parsed;
try { parsed = JSON.parse(stdout); } catch (_e) { parsed = { ok: false, raw: stdout }; }
return [{ json: parsed }];
